def main():
    jobs = [json.loads(l) for l in JOBS_PATH.read_text(encoding='utf-8').splitlines() if l.strip()]

    verdicts = []
    missing = []
    violations_by_key: dict[str, list[str]] = {}
    for j in jobs:
        key = f"{j['word']}|{j['pos']}|{j['cefr']}"
        v = M3_VERDICTS.get(key)
        if not v:
            missing.append(key)
            continue
        gloss, sep, count, rule = v

        # Validate gate (auto-detectable: separator/count consistency, word count,
        # headword-as-chunk — covers self-ref + leak). Per-entry skip pattern:
        # bad verdict goes to violations list, NOT verdicts list, so producer
        # can see exactly which keys need regen.
        errs = validate_verdict(j['word'], gloss, sep, count)
        if errs:
            violations_by_key[key] = errs
            continue

        verdicts.append({
            'word': j['word'],
            'pos': j['pos'],
            'cefr': j['cefr'],
            'def': j['def'],
            'gloss': gloss,
            'hash': j['hash'],
            'decision': 'gloss',
            'rule_applied': rule,
            'separator': sep,
            'count': count,
        })

    OUT.write_text(json.dumps(verdicts, ensure_ascii=False, indent=2), encoding='utf-8')
    print(f'Wrote {len(verdicts)} verdicts to {OUT}')

    if violations_by_key:
        VIOLATIONS_OUT.write_text(
            json.dumps(violations_by_key, ensure_ascii=False, indent=2),
            encoding='utf-8',
        )
        summarize_violations(violations_by_key)
        print(f'Violations written to {VIOLATIONS_OUT}')

    if missing:
        print(f'MISSING {len(missing)} jobs (no M3 verdict):')
        for k in missing[:10]:
            print(f'  {k}')


if __name__ == '__main__':
    main()
